import axios from "axios";
import React, { useEffect, useState } from "react";
import { useParams } from "react-router";
import requests from "../requests";
import MovieCard from "./MovieCard";
import empty from "../images/empty.svg";
import Loading from "./Loading";

function Discover() {
  const [isLoading, setisLoading] = useState(false);
  const [mediaType, setmediaType] = useState("movie");
  const { genreID, genreName } = useParams();

  const [movies, setmovies] = useState([]);
  const [page, setpage] = useState(1);
  const fetchUrl = `https://api.themoviedb.org/3/discover/${mediaType}?api_key=${requests.apiKey}&with_genres=${genreID}&page=${page}`;
  useEffect(() => {
    const discoverIt = async () => {
      setisLoading(true);
      const res = await axios.get(fetchUrl);
      setmovies([...movies, ...res.data.results]);
      setisLoading(false);
    };
    discoverIt();
  }, [mediaType, genreID, genreName, page]);

  return (
    <div className="Discover">
      {isLoading && <Loading />}
      <h1>{genreName}</h1>
      <div className="mediaTypeHolder">
        <span
          onClick={() => {
            setmediaType("movie");
            setmovies([]);
          }}
          id="movie"
          className={mediaType === "movie" ? "on" : "off"}
        >
          movies
        </span>
        <span
          id="tv"
          onClick={() => {
            setmediaType("tv");
            setmovies([]);
          }}
          className={mediaType === "tv" ? "on" : "off"}
        >
          tv shows
        </span>
      </div>
      <div className="inner_all_movies_holder">
        {movies.length < 1 && (
          <div className="emptyDataHolder">
            <img src={empty} alt="empty" />
            <h1>no data for this genre yet</h1>
          </div>
        )}
        {movies.map((movie, key) => (
          <MovieCard mediaType={mediaType} movie={movie} key={key} />
        ))}
      </div>
      <div className="load_more_holder">
        {movies.length > 1 && (
          <button className="more_button_2" onClick={() => setpage(page + 1)}>
            more
          </button>
        )}
      </div>
    </div>
  );
}

export default Discover;
