import React from "react";
import { Link } from "react-router-dom";

function WatchListButton({ watchListLen }) {
  return (
    <button className="WatchListButton" id="WatchListButton">
      <Link to="/watch-list">
        watch list
        {watchListLen !== 0 ? <span class="badge">{watchListLen}</span> : ""}
      </Link>
    </button>
  );
}

export default WatchListButton;
