import React from 'react'
import SearchBar from './SearchBar'
import WatchListButton from './WatchListButton'
import { useMediaQuery } from 'react-responsive'

function MenuBox({setMovieQuery,movies,setMovies,showSearchMenu,setShowSearchMenu,watchListLen}) {
    const isBigScreen = useMediaQuery({ query: '(min-width: 564px)' })
    return (
        <div className="MenuBox" id="MenuBox">
            {isBigScreen && <SearchBar Class="SearchBar" setMovieQuery={setMovieQuery} movies={movies} setMovies={setMovies} showSearchMenu={showSearchMenu} setShowSearchMenu={setShowSearchMenu}/>}
            <WatchListButton watchListLen={watchListLen}/>
        </div>
    )
}

export default MenuBox
